// ===== AUTH — Asisten Petugas SE2026 =====
// Script ini DIPAKAI BERSAMA di 4 halaman (index.html, assistencalc.html,
// rootadmin.html, ocrkkktp.html). Isinya HANYA logika login/otorisasi/
// redirect -- TIDAK ADA logika kalkulator/bisnis app di sini, supaya
// index.html (gerbang akses) tidak bisa dipakai untuk menduplikasi
// aplikasi Asisten PPL.
//
// Cara kerja tiap halaman ditentukan otomatis:
//   - Kalau ada elemen #lockScreen di halaman -> ini index.html (gerbang
//     akses) -> jalankan logika form login + auto-redirect.
//   - Kalau tidak ada -> ini halaman app (assistencalc/rootadmin/ocrkkktp)
//     -> jalankan logika PENJAGA (guard): pastikan sesi valid (dan level
//     admin kalau halaman mensyaratkannya), atau tendang balik ke gerbang.
//
// Tiap halaman app menandai kebutuhannya lewat variabel global SEBELUM
// memuat file ini:
//   window.PAGE_REQUIRES_ADMIN  = true/false (default false)
//   window.PAGE_REQUIRES_ONLINE = true/false (default false)

const URL_APPS_SCRIPT = 'https://script.google.com/macros/s/AKfycbzUMVTcWHvlpRiWK7runS6kg0tZrdmEzLJvKjCgenKGm3pZkc4hbfaASmP-bd5tb3j6sw/exec';
window.APPS_SCRIPT_URL = URL_APPS_SCRIPT;

const LOCK_STORAGE_KEY = 'se2026_kode_aktif_v1';
const DEVICE_ID_KEY = 'se2026_device_uuid_v1';
const NAMA_STORAGE_KEY = 'se2026_nama_pengguna_v1';
const EXPIRY_STORAGE_KEY = 'se2026_expiry_cutoff_v1';
const LEVEL_STORAGE_KEY = 'se2026_level_v1';
const SHOW_DISCLAIMER_ONCE_KEY = 'se2026_show_disclaimer_once';

// showToast dipakai di banyak tempat (copy device id, logout, dsb). Kalau
// app.min.js sudah mendefinisikan versi yang lebih lengkap (di halaman
// assistencalc.html), jangan ditimpa -- pakai punya app.min.js.
if (typeof window.showToast !== 'function') {
  window.showToast = function (msg) {
    const el = document.getElementById('toast');
    if (!el) return;
    el.textContent = msg;
    el.classList.add('show');
    setTimeout(() => el.classList.remove('show'), 2500);
  };
}

// ===== Device ID (persisten per HP) =====
function getOrCreateDeviceId() {
  let id = localStorage.getItem(DEVICE_ID_KEY);
  if (id) return id;
  id = (window.crypto && crypto.randomUUID)
    ? crypto.randomUUID()
    : ('dev-' + Date.now().toString(36) + '-' + Math.random().toString(36).slice(2) + Math.random().toString(36).slice(2));
  id = id.toUpperCase();
  try { localStorage.setItem(DEVICE_ID_KEY, id); } catch (e) {}
  return id;
}
function renderDeviceIdUI() {
  const el = document.getElementById('deviceIdText');
  if (el) el.textContent = getOrCreateDeviceId();
}
function copyDeviceId() {
  const id = getOrCreateDeviceId();
  const done = () => showToast('📋 Device ID tersalin');
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(id).then(done).catch(() => fallbackCopyDeviceId(id, done));
  } else {
    fallbackCopyDeviceId(id, done);
  }
}
function fallbackCopyDeviceId(text, done) {
  try {
    const ta = document.createElement('textarea');
    ta.value = text; ta.style.position = 'fixed'; ta.style.opacity = '0';
    document.body.appendChild(ta); ta.select(); document.execCommand('copy');
    document.body.removeChild(ta); done();
  } catch (e) {}
}

function getStoredKode() { return localStorage.getItem(LOCK_STORAGE_KEY); }
function getStoredNama() { return localStorage.getItem(NAMA_STORAGE_KEY); }
function getStoredLevel() { return localStorage.getItem(LEVEL_STORAGE_KEY) || 'biasa'; }

function simpanExpiryLokal(iso) {
  try { if (iso) localStorage.setItem(EXPIRY_STORAGE_KEY, iso); else localStorage.removeItem(EXPIRY_STORAGE_KEY); } catch (e) {}
}
function getExpiryLokal() {
  const iso = localStorage.getItem(EXPIRY_STORAGE_KEY);
  if (!iso) return null;
  const d = new Date(iso);
  return isNaN(d.getTime()) ? null : d;
}
function sudahKedaluwarsaLokal() {
  const cutoff = getExpiryLokal();
  if (!cutoff) return false;
  return new Date() > cutoff;
}
function hapusSesiLokal() {
  localStorage.removeItem(LOCK_STORAGE_KEY);
  localStorage.removeItem(NAMA_STORAGE_KEY);
  localStorage.removeItem(EXPIRY_STORAGE_KEY);
  localStorage.removeItem(LEVEL_STORAGE_KEY);
}

// Balikin: 'invalid' (belum login) | 'expired' (lewat batas waktu lokal)
// | 'biasa' | 'admin'
function cekStatusSesi() {
  const kode = getStoredKode();
  if (!kode) return 'invalid';
  if (sudahKedaluwarsaLokal()) return 'expired';
  return getStoredLevel() === 'admin' ? 'admin' : 'biasa';
}

function redirectKeGerbang() { location.href = './index.html'; }
function redirectKeApp() { location.href = './assistencalc.html'; }
function redirectKeAdmin() { location.href = './rootadmin.html'; }

// ===== Verifikasi ulang ke server (dipanggil saat online) =====
async function verifikasiKodeBackground(kode) {
  const controller = new AbortController();
  const t = setTimeout(() => controller.abort(), 5000);
  try {
    const device = encodeURIComponent(getOrCreateDeviceId());
    const url = URL_APPS_SCRIPT + '?action=cek&kode=' + encodeURIComponent(kode) + '&device=' + device;
    const res = await fetch(url, { signal: controller.signal });
    const data = await res.json();
    if (!data.success) return;
    if (data.status === 'aktif') {
      simpanExpiryLokal(data.expiresAt || null);
      if (data.level) localStorage.setItem(LEVEL_STORAGE_KEY, data.level);
      return;
    }
    // status: 'belum' | 'expired' | 'aktif_beda_device' -> paksa logout, balik ke gerbang
    hapusSesiLokal();
    redirectKeGerbang();
  } catch (e) {
    // offline / timeout -> biarkan, tidak dipaksa logout
  } finally {
    clearTimeout(t);
  }
}

// ===== Logout (dipakai di semua halaman app) =====
async function logoutAkun() {
  const kode = getStoredKode();
  if (!kode) { redirectKeGerbang(); return; }

  if (!navigator.onLine) {
    alert('⚠️ Tidak bisa logout dalam kondisi offline.\n\nLogout butuh koneksi internet supaya data terbaru di HP ini tersimpan ke server dulu, dan supaya kode aktivasi benar-benar dilepas dari perangkat ini. Sambungkan ke internet lalu coba lagi.');
    return;
  }
  if (!confirm('Logout dari aplikasi ini?\n\nKode aktivasi akan dilepas dari perangkat ini dan bisa dipakai login di perangkat lain. Data yang sudah tersimpan di HP ini TIDAK terhapus.')) return;

  try {
    if (typeof window.pushDataSinkron === 'function') {
      showToast('⏳ Menyimpan data terakhir…');
      await window.pushDataSinkron();
    }
    const device = encodeURIComponent(getOrCreateDeviceId());
    const url = URL_APPS_SCRIPT + '?action=logout&kode=' + encodeURIComponent(kode) + '&device=' + device;
    const res = await fetch(url);
    const data = await res.json();
    if (data.success) {
      hapusSesiLokal();
      showToast('✅ Logout berhasil, data tersimpan');
      setTimeout(redirectKeGerbang, 400);
    } else {
      showToast('❌ ' + (data.message || 'Gagal logout'));
    }
  } catch (e) {
    showToast('❌ Gagal terhubung ke server, logout dibatalkan');
  }
}

window.getOrCreateDeviceId = getOrCreateDeviceId;
window.copyDeviceId = copyDeviceId;
window.logoutAkun = logoutAkun;
window.verifikasiKodeBackground = verifikasiKodeBackground;
window.getStoredKode = getStoredKode;
window.getStoredNama = getStoredNama;
window.getStoredLevel = getStoredLevel;

// =====================================================================
// ================  LOGIKA KHUSUS GERBANG (index.html)  ===============
// =====================================================================
const lockScreen = document.getElementById('lockScreen');

if (lockScreen) {
  const lockBox = document.getElementById('lockBox');
  const inputKode = document.getElementById('kodeAkses');
  const inputNama = document.getElementById('namaPengguna');
  const lockMsg = document.getElementById('lockMsg');
  const btnAktivasi = document.getElementById('btnAktivasi');

  function showLockMsg(text, type) {
    if (!lockMsg) return;
    lockMsg.textContent = text;
    lockMsg.className = 'lock-msg show ' + type;
  }
  function hideLockMsg() { if (lockMsg) lockMsg.className = 'lock-msg'; }
  function setLockLoading(loading) {
    if (!btnAktivasi) return;
    btnAktivasi.disabled = loading;
    btnAktivasi.textContent = loading ? 'Memproses…' : 'Masuk';
  }

  async function aktivasiKode() {
    const kode = (inputKode.value || '').trim().toUpperCase();
    const nama = (inputNama && inputNama.value || '').trim();

    if (!nama) return showLockMsg('⚠️ Nama Pengguna wajib diisi.', 'error');
    if (!kode) return showLockMsg('⚠️ Kode Aktivasi wajib diisi.', 'error');
    if (!navigator.onLine) return showLockMsg('⚠️ Butuh koneksi internet untuk login pertama kali.', 'error');

    setLockLoading(true);
    hideLockMsg();
    try {
      const device = getOrCreateDeviceId();
      const url = URL_APPS_SCRIPT + '?action=aktivasi&kode=' + encodeURIComponent(kode)
        + '&device=' + encodeURIComponent(device) + '&nama=' + encodeURIComponent(nama);
      const res = await fetch(url);
      const data = await res.json();
      setLockLoading(false);

      if (data.success) {
        localStorage.setItem(LOCK_STORAGE_KEY, kode);
        localStorage.setItem(NAMA_STORAGE_KEY, nama);
        simpanExpiryLokal(data.expiresAt || null);
        const level = data.level || 'biasa';
        localStorage.setItem(LEVEL_STORAGE_KEY, level);
        showLockMsg('✅ ' + (data.message || 'Login berhasil.'), 'info');
        if (level !== 'admin') localStorage.setItem(SHOW_DISCLAIMER_ONCE_KEY, '1');
        setTimeout(() => { level === 'admin' ? redirectKeAdmin() : redirectKeApp(); }, 500);
      } else {
        showLockMsg('❌ ' + (data.message || 'Kode aktivasi tidak valid.'), 'error');
        if (lockBox) { lockBox.style.animation = 'shake .4s'; setTimeout(() => { lockBox.style.animation = ''; }, 400); }
      }
    } catch (e) {
      setLockLoading(false);
      showLockMsg('❌ Gagal terhubung ke server. Cek koneksi internet.', 'error');
    }
  }
  window.aktivasiKode = aktivasiKode;

  if (inputKode) inputKode.addEventListener('keydown', (e) => { if (e.key === 'Enter') aktivasiKode(); });
  if (inputNama) inputNama.addEventListener('keydown', (e) => { if (e.key === 'Enter') aktivasiKode(); });

  // ---- Modal sambutan (15 detik) ----
  var _welcomeCountdownTimer = null;
  function tampilkanModalWelcome() {
    const modal = document.getElementById('modalWelcome');
    const label = document.getElementById('welcomeCountdown');
    if (!modal) return;
    let sisa = 15;
    if (label) label.textContent = String(sisa);
    modal.style.display = 'flex';
    if (_welcomeCountdownTimer) clearInterval(_welcomeCountdownTimer);
    _welcomeCountdownTimer = setInterval(() => {
      sisa -= 1;
      if (label) label.textContent = String(Math.max(sisa, 0));
      if (sisa <= 0) tutupModalWelcome();
    }, 1000);
  }
  function tutupModalWelcome() {
    const modal = document.getElementById('modalWelcome');
    if (modal) modal.style.display = 'none';
    if (_welcomeCountdownTimer) { clearInterval(_welcomeCountdownTimer); _welcomeCountdownTimer = null; }
  }
  window.tutupModalWelcome = tutupModalWelcome;

  // ---- Init: cek sesi tersimpan -> auto-redirect kalau valid (online/offline) ----
  (function () {
    renderDeviceIdUI();
    const status = cekStatusSesi();

    if (status === 'biasa') { redirectKeApp(); return; }
    if (status === 'admin') {
      if (navigator.onLine) { redirectKeAdmin(); return; }
      // Panel admin butuh online. Offline -> tetap alihkan ke app utama
      // (yang memang didesain bisa dipakai offline) daripada macet di gerbang.
      redirectKeApp(); return;
    }
    if (status === 'expired') hapusSesiLokal();

    // Tidak ada sesi valid -> tampilkan form login seperti biasa.
    tampilkanModalWelcome();
    const namaTersimpan = getStoredNama();
    if (namaTersimpan && inputNama) inputNama.value = namaTersimpan;
  })();

} else {
  // ===================================================================
  // ========  LOGIKA PENJAGA UNTUK HALAMAN APP (bukan gerbang)  ========
  // ===================================================================
  const BUTUH_ADMIN = window.PAGE_REQUIRES_ADMIN === true;
  const BUTUH_ONLINE = window.PAGE_REQUIRES_ONLINE === true;

  function tampilkanPesanButuhOnline() {
    const el = document.getElementById('needOnlineMsg');
    if (el) { el.style.display = 'block'; }
    document.querySelectorAll('[data-need-online]').forEach(n => { n.style.display = 'none'; });
  }

  (function jalankanPenjagaHalaman() {
    const status = cekStatusSesi();

    if (status === 'invalid' || status === 'expired') {
      if (status === 'expired') hapusSesiLokal();
      redirectKeGerbang();
      return;
    }
    if (BUTUH_ADMIN && status !== 'admin') {
      // Halaman khusus admin diakses user biasa -> lempar ke app biasa.
      redirectKeApp();
      return;
    }
    if (BUTUH_ONLINE && !navigator.onLine) {
      tampilkanPesanButuhOnline();
      return;
    }

    // Sesi valid & syarat halaman terpenuhi -> tampilkan nama user kalau ada elemennya
    const namaEl = document.getElementById('namaUserAktif');
    if (namaEl) namaEl.textContent = getStoredNama() || 'Pengguna';

    // Tampilkan disclaimer sekali kalau baru saja login (ditandai dari gerbang)
    if (localStorage.getItem(SHOW_DISCLAIMER_ONCE_KEY) === '1') {
      localStorage.removeItem(SHOW_DISCLAIMER_ONCE_KEY);
      if (typeof window.tampilkanDisclaimer === 'function') window.tampilkanDisclaimer();
    }

    if (navigator.onLine) {
      verifikasiKodeBackground(getStoredKode());
      if (typeof window.tarikDataSinkron === 'function') window.tarikDataSinkron(getStoredKode(), getOrCreateDeviceId());
    }
  })();

  // Cek ulang tiap 90 detik selama halaman terbuka (jalan offline juga
  // untuk bagian pengecekan kedaluwarsa lokal).
  setInterval(function () {
    const status = cekStatusSesi();
    if (status === 'invalid' || status === 'expired') {
      if (status === 'expired') hapusSesiLokal();
      redirectKeGerbang();
      return;
    }
    if (BUTUH_ADMIN && status !== 'admin') { redirectKeApp(); return; }
    if (navigator.onLine) verifikasiKodeBackground(getStoredKode());
  }, 90000);
}

// ===== Modal Peringatan & Persetujuan (identitas responden) =====
// Ditampilkan sekali setiap kali user BARU SAJA login sebagai level
// biasa (ditandai lewat SHOW_DISCLAIMER_ONCE_KEY dari gerbang), muncul
// di halaman assistencalc.html.
function tampilkanDisclaimer() {
  const modal = document.getElementById('modalDisclaimer');
  const chk = document.getElementById('chkDisclaimerSetuju');
  const btn = document.getElementById('btnLanjutDisclaimer');
  if (!modal) return;
  if (chk) chk.checked = false;
  if (btn) { btn.disabled = true; btn.style.cursor = 'not-allowed'; btn.style.opacity = '0.6'; }
  modal.style.display = 'flex';
}
function toggleTombolDisclaimer() {
  const chk = document.getElementById('chkDisclaimerSetuju');
  const btn = document.getElementById('btnLanjutDisclaimer');
  if (!chk || !btn) return;
  btn.disabled = !chk.checked;
  btn.style.cursor = chk.checked ? 'pointer' : 'not-allowed';
  btn.style.opacity = chk.checked ? '1' : '0.6';
}
function konfirmasiDisclaimer() {
  const chk = document.getElementById('chkDisclaimerSetuju');
  if (!chk || !chk.checked) return;
  const modal = document.getElementById('modalDisclaimer');
  if (modal) modal.style.display = 'none';
}
window.tampilkanDisclaimer = tampilkanDisclaimer;
window.toggleTombolDisclaimer = toggleTombolDisclaimer;
window.konfirmasiDisclaimer = konfirmasiDisclaimer;
